var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"후우…….","JPN":"ふう……","ENG":"Whew...","TWN":"呼……"},"stage":{"bg":"HALL","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"할 수 없어. 루시아 릿지.","JPN":"無理無理無理。ルシア・リッジ。","ENG":"This is impossible, Lucia Ridge.","TWN":"太難了。"},"stage":{"bg":"HALL","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"저건 황금 고블린이 아니라 고블린 족장쯤은 되겠어.","JPN":"あれはただのゴールデンゴブリンじゃなくて、ゴブリン隊長レベルだって。","ENG":"That thing isn't just some goblin grunt, it's more like a goblin chief.","TWN":"那不是黃金哥布林，而是哥布林族長吧。"},"stage":{"bg":"HALL","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"게다가 CRF도 이젠 진짜 바닥이야…….","JPN":"それにCRFもマジで底をついてる……","ENG":"And my CRF... it's completely drained.","TWN":"CRF現在真的已經見底了……"},"stage":{"bg":"HALL","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"작전 변경이다.","JPN":"作戦変更だ。","ENG":"Change of plans.","TWN":"變更作戰計畫。"},"stage":{"bg":"HALL","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L13_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"곤죽이 되더라도 저택 밖으로…….","JPN":"防御度外視で、何とか邸宅の外へ……","ENG":"Even if I get beaten to a pulp, I have to get out of this mansion...","TWN":"不管怎樣都要離開這座屋子……"},"stage":{"bg":"HALL","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L16_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_QM","text":{"KOREA":"사냥감을…… 구석에 몰아넣어…….","JPN":"獲物を……追い込み……","ENG":"Hunt... Corner the prey...","TWN":"把獵物……逼到角落……"},"stage":{"bg":"HALL","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_EXPLOSION_ATTACK_BIG_02"},{"id":"L17_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_QM","text":{"KOREA":"피가…… 필요해…… 완전한…… 피가……!","JPN":"血が……欲しい……完全な……血が……！","ENG":"I need... blood... pure... blood...!","TWN":"血……需要……完整的……血……!"},"stage":{"bg":"HALL","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"젠장, 저택 출구로 향하는 복도가……!","JPN":"くそ、邸宅の出口に繋がる廊下が……！","ENG":"Damn it, the hallway to the exit...!","TWN":"該死，通往屋子出口的走廊……！"},"stage":{"bg":"HALL","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"허세 부리지 말고, 그냥 도망갈걸!","JPN":"見栄張らずに逃げればよかった！","ENG":"Should've swallowed my pride and just run!","TWN":"別逞強了，趕緊逃跑吧！"},"stage":{"bg":"HALL","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"멍청하게 그 변태 수녀나 도망치게 하고.","JPN":"バカみたいにあの変態シスターだけ逃がしちゃって。","ENG":"Instead of letting that perverted nun escape...","TWN":"真是蠢，讓那個變態修女逃走。"},"stage":{"bg":"HALL","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"분명 그 녀석, 성황청에 도움만 요청하고 꽁무니 뺐을 거라고.","JPN":"あいつ、聖皇庁に連絡してさっさと帰っちゃったに違いない。","ENG":"Bet she ran off after calling the Holy Curia for help.","TWN":"那個傢伙肯定只是向聖皇廳求助後就溜走了。"},"stage":{"bg":"HALL","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"<color=#ffd34c>신께서 이단을 용서하지 않으셨다!</color> 라고 합리화했을 거란 말이야!","JPN":"<color=#ffd34c>神は異端を許されなかった！</color>とか言ってさ！","ENG":"Probably justified it with, <color=#ffd34c>\\"God does not forgive heretics!\\"</color> and took off.","TWN":"肯定又會說<color=#ffd34c>神不會寬恕異端！</color> 這種官腔！"},"stage":{"bg":"HALL","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_QM","text":{"KOREA":"나는 한층 더…… 우월한 존재가…….","JPN":"私はよりいっそう……優越な存在に……","ENG":"I shall ascend... to a superior existence...","TWN":"我將變得……更加卓越……"},"stage":{"bg":"HALL","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_QM","text":{"KOREA":"침식을…… 이겨내…….","JPN":"侵食を……乗り越え……","ENG":"Overcome... the Corruption...","TWN":"戰勝……侵蝕……"},"stage":{"bg":"HALL","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_HOWLING_02"},{"id":"L34_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"크윽……!","JPN":"くうっ……！","ENG":"Kgh...!","TWN":"呃……!"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"나는…… 이대로 죽을 생각 없어……!","JPN":"私は……このまま死ぬつもりはない……！","ENG":"I'm... not dying here...!","TWN":"我……我不想就這樣死去……！"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"이 병을……","JPN":"この病気を……","ENG":"This sickness...","TWN":"這個病……"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"AGNES_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"이 아이가 붉은 달 감염자란 말이지?","JPN":"この子が赤い月の感染者ね？","ENG":"So, this girl is a Red Moon afflicted?","TWN":"這個孩子是紅月感染者嗎？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"AGNES_VATICAN_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NPC_GIRL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NPC_GIRL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"AGNES_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"겁을 먹은 것도 아니고, 그렇다고 화가 난 것도 아니고…….","JPN":"怯えているわけでもなく、だからと言って怒っているわけでもなく……","ENG":"She's not scared... but she's not angry either.","TWN":"既不是害怕，也不是生氣……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"AGNES_VATICAN_SUPPLEMENT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"AGNES_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"이렇게 전부 놔 버린 얼굴은 정말 오랜만에 보네.","JPN":"ここまですべてを諦めた顔を見るのは久しぶりね。","ENG":"It's been a long time since I've seen a face that's just... given up.","TWN":"這個樣子，真是好久沒見過了。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"AGNES_VATICAN_SUPPLEMENT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NPC_GIRL","text":{"KOREA":"여긴……어디죠?","JPN":"ここは……どこですか？","ENG":"Where... am I?","TWN":"這是……哪裡？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NPC_GIRL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"AGNES_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"여긴 발렌티누스 수도원이야.","JPN":"ここはバレンチヌス修道院よ。","ENG":"You're at the Valentinus Monastery.","TWN":"這裡是聖華倫修道院。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"AGNES_VATICAN_SUPPLEMENT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"AGNES_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"넌 우리 숙원을 이뤄줄 중요한 그릇이고.","JPN":"そしてあなたは、私たちの宿願を叶えてくれる大事な器。","ENG":"And you... are a very important vessel for our wish.","TWN":"你是實現我們願望的重要器皿。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"AGNES_VATICAN_SUPPLEMENT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NPC_GIRL","text":{"KOREA":"그릇……?","JPN":"器……？","ENG":"...Vessel?","TWN":"器皿……？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NPC_GIRL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"AGNES_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"일단 뭐 좀 먹을래?","JPN":"とりあえず何か食べる？","ENG":"Hungry? Want something to eat?","TWN":"你要先吃點什麼嗎？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"AGNES_VATICAN_SUPPLEMENT_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NPC_GIRL","text":{"KOREA":"……언니, 혼자죠?","JPN":"……お姉さん、1人ですよね？","ENG":"…Are you alone?","TWN":"……姊姊，一個人嗎？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NPC_GIRL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"AGNES_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"응?","JPN":"うん？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"AGNES_VATICAN_SUPPLEMENT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NPC_GIRL","text":{"KOREA":"여기…… 사람 냄새가 하나도 안 나요.","JPN":"ここ……人の匂いが全然しません。","ENG":"This place... doesn't smell like people.","TWN":"這裡……一點人味都沒有。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NPC_GIRL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"AGNES_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"다짜고짜…… 당돌하네.","JPN":"中々ストレートな物言いなのね。","ENG":"Hmm... Quite bold for a first impression.","TWN":"這可……真是冒犯到我了。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"AGNES_VATICAN_SUPPLEMENT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NPC_GIRL","text":{"KOREA":"윽, 달콤한 냄새…… 배고파…….","JPN":"うっ、甘い匂い……お腹空いた……","ENG":"Ugh, that sweet smell... I'm hungry...","TWN":"呃，甜甜的味道……好餓……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NPC_GIRL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"AGNES_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"에그타르트 냄새야.","JPN":"エッグタルトの匂いよ。","ENG":"That's egg tart you're smelling.","TWN":"是蛋撻的香味。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"AGNES_VATICAN_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"AGNES_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"잠시만 기다릴래?","JPN":"少し待ってくれる？","ENG":"Wait here for a bit.","TWN":"等一下好嗎？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"AGNES_VATICAN_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NPC_GIRL","text":{"KOREA":"……배불러.","JPN":"……お腹いっぱい。","ENG":"...I'm full.","TWN":"……好飽。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NPC_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"AGNES_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"후훗, 맛있게 먹어줘서 다행이네.","JPN":"ふふっ、美味しく食べてくれてよかったわ。","ENG":"Haha. Glad you liked it.","TWN":"呵呵，你吃得開心就好。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"AGNES_VATICAN_SUPPLEMENT_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"AGNES_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"이제야 좀 애다운 얼굴이 됐어.","JPN":"やっと子供らしい顔になったわね。","ENG":"You finally look a little more like a child.","TWN":"現在終於有點孩子的樣子了。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"AGNES_VATICAN_SUPPLEMENT_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NPC_GIRL","text":{"KOREA":"저는…… 이제 어떻게 되는 거죠?","JPN":"私は……これからどうなるんですか？","ENG":"So... what happens to me now?","TWN":"我之後……會怎麼樣？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NPC_GIRL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"AGNES_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"너는 이제 그릇이 될 준비를 하는 거야.","JPN":"あなたはこれから、器になる準備をすることになる。","ENG":"You prepare to become a vessel.","TWN":"你現在正在準備成為器皿。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"AGNES_VATICAN_SUPPLEMENT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NPC_GIRL","text":{"KOREA":"그릇이…… 뭔데요?","JPN":"器って……何ですか？","ENG":"What's a... vessel?","TWN":"器皿……是什麼？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NPC_GIRL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"AGNES_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"AGNES_VATICAN_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"AGNES_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"이젠 나도 모르겠어.","JPN":"私にもわからないわ。","ENG":"I don't know either.","TWN":"我也不知道。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"AGNES_VATICAN_SUPPLEMENT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"AGNES_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"나름 한식구라고 생각했던 사람들이 그걸 알아내려다가 다 죽었거든.","JPN":"それなりに家族だと思ってた人たち全部、それを研究する途中で死んじゃったの。","ENG":"The people I once called family all died trying to figure that out.","TWN":"那些我曾經視為一家人的人，都在試圖揭開那個秘密時死去了。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"AGNES_VATICAN_SUPPLEMENT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NPC_GIRL","text":{"KOREA":"식구…… 언니도 가족을 잃었어요?","JPN":"お姉さんも……家族を……","ENG":"Family… Did you lose your family, too?","TWN":"家人……姊姊也失去家人了嗎？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NPC_GIRL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"AGNES_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"가족? 글쎄, 적어도 같은 꿈을 좇던 사람들이었어.","JPN":"同じ夢を追っていた人たちだった。","ENG":"Family I say… Well, at least we were pursuing the same dream.","TWN":"家人？嗯，至少是追逐同一個夢想的人。"},"stage":{"bg":"SS_ESPR_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"AGNES_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"신을 관측하고 싶어했지.","JPN":"神を観測するという。","ENG":"They wanted to witness God.","TWN":"可能是想窺探神明吧。"},"stage":{"bg":"SS_ESPR_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"AGNES_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"그런데…… 나만 빼고 다들 죽어버렸지 뭐야?","JPN":"でも……私を置いてみんな死んじゃったわ。","ENG":"But in the end... I was the only one left alive.","TWN":"但是……只有我一個人活了下來，其他人都死了。"},"stage":{"bg":"SS_ESPR_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"AGNES_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"이제 와서 생각해보면 정말 미련한 짓이었는데.","JPN":"今思うと、本当に愚かな考えだったわね。","ENG":"Looking back now, it was all such a foolish pursuit.","TWN":"現在想想真是件愚蠢的事情。"},"stage":{"bg":"SS_ESPR_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NPC_GIRL","text":{"KOREA":"신……?","JPN":"神……？","ENG":"God...?","TWN":"神……？"},"stage":{"bg":"SS_ESPR_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NPC_GIRL","text":{"KOREA":"언니는 신을 불러올 수 있나요?","JPN":"お姉さんは、神様を呼べるんですか？","ENG":"Can you... summon God?","TWN":"姊姊能召喚神明嗎？"},"stage":{"bg":"SS_ESPR_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"AGNES_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"응?","JPN":"うん？","ENG":"Huh?","TWN":"嗯?"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"AGNES_VATICAN_SUPPLEMENT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NPC_GIRL","text":{"KOREA":"시, 신을 불러오면 제 병을 고쳐줄 수 있나요?","JPN":"か、神様を呼んだら、私の病気も治してもらえますか？","ENG":"If you summon God... can He cure me?","TWN":"如果召喚神明的話，能治好我的病嗎？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NPC_GIRL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"AGNES_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"……아니, 신은 누구의 부름에도 응답하지 않아.","JPN":"……いいえ、神は誰の呼びかけにも応えてくれないわ。","ENG":"...No. God doesn't answer anyone's call.","TWN":"……不，神不會回應任何人的呼喚。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"AGNES_VATICAN_SUPPLEMENT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"AGNES_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"병을 고치고 싶니?","JPN":"病気を治したいの？","ENG":"Do you want to be cured?","TWN":"想治病嗎？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"AGNES_VATICAN_SUPPLEMENT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NPC_GIRL","text":{"KOREA":"네. 이, 이 병은 주변 사람을 상처 입혀요.","JPN":"はい。こ、この病気は周りの人を傷つけるんです。","ENG":"Yes. Th-this sickness... it hurts the people around me.","TWN":"是的，這，這種病會傷害周圍的人。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NPC_GIRL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NPC_GIRL","text":{"KOREA":"저는…… 맛있는 음식을 준 언니를 다치게 하고 싶지 않아요.","JPN":"私は……美味しいものをくれたお姉さんを傷つけたくないです。","ENG":"But I don't want to hurt you... You gave me food.","TWN":"我……不想傷害給我好吃食物的姊姊。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NPC_GIRL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NPC_GIRL","text":{"KOREA":"그릇……이 되면 병을 고칠 수 있는 거예요?","JPN":"器……になったら、病気も治せるんですか？","ENG":"If I become a vessel... will it cure me?","TWN":"成為器皿……就能治好病嗎？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NPC_GIRL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"AGNES_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"……물론이지.","JPN":"……もちろんよ。","ENG":"...Of course.","TWN":"……當然可以。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"AGNES_VATICAN_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"AGNES_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"잘 먹고, 잘 자고, 잘 자라면 훌륭한 그릇이 되는 거란다.","JPN":"よく食べて、よく寝て、すくすく育ったら、立派な器になるの。","ENG":"Eat well, sleep well, and grow strong. That's how you'll become a fine vessel.","TWN":"吃得好，睡得好，長得好，就會成為一個了不起的器皿。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"AGNES_VATICAN_SUPPLEMENT_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NPC_GIRL","text":{"KOREA":"네? 그, 그거면 되는 거예요?","JPN":"え？　そ、それだけでいいんですか？","ENG":"Huh? Th-that's all I have to do?","TWN":"嗯？這樣就可以嗎？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NPC_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"AGNES_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"참 쉽지?","JPN":"簡単でしょう？","ENG":"Simple, right?","TWN":"很簡單吧？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"AGNES_VATICAN_SUPPLEMENT_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"AGNES_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"그럼 배부르게 먹었으니 언니랑 푹 자러 갈까?","JPN":"つまり、お腹いっぱい食べたあなたは、これからお姉さんと一緒にぐっすり寝ればいいってことなのよ。","ENG":"Now that you're full, why don't we go get some rest?","TWN":"那吃飽了，要不要跟姊姊一起去睡個好覺？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"AGNES_VATICAN_SUPPLEMENT_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NPC_GIRL","text":{"KOREA":"아…….","JPN":"あ……","ENG":"Uh...","TWN":"啊……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NPC_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NPC_GIRL","text":{"KOREA":"네!","JPN":"はい！","ENG":"Okay!","TWN":"好！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NPC_GIRL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"주마등?","JPN":"走馬灯？","ENG":"Was that my life flashing before my eyes?","TWN":"人生跑馬燈？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"아, 아직 난 죽을 생각 없는데……?!","JPN":"ま、まだ死ぬつもりはないのに……！？","ENG":"No way. I'm not dying yet...!","TWN":"啊，我還沒打算死呢……！？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_QM","text":{"KOREA":"역시 멍멍이는 내가 없으면 안 된다니까.","JPN":"やっぱり、ワンちゃんは私がいないとダメね。","ENG":"I knew it. Puppy is helpless without me.","TWN":"狗狗果然沒有我不行呢。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE","voice":"AB_UI_UNIT_VOICE_OPR_AGNES_COMMANDER_IN_TRAILER_4"},{"id":"L32_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_QM","text":{"KOREA":"뭐, 그런 표정도 나쁘지 않네.","JPN":"ま、そんな顔も悪くないわ。","ENG":"Well... that's not a bad look on you.","TWN":"嗯，那種表情也不錯呢。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_OPR_AGNES_COMMANDER_IN_TRAILER_5"},{"id":"L33_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_QM","text":{"KOREA":"이 장면도 저장해 둬야지.","JPN":"この場面も保存しておこうっと。","ENG":"I should capture this moment, too.","TWN":"這個畫面也要保存下來。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_OPR_AGNES_COMMANDER_IN_TRAILER_6"},{"id":"L35_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"이 목소리는?","JPN":"この声は？","ENG":"That voice...","TWN":"這聲音是？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"으긋, 이건 CRF 소모가 심해서 아껴두던 건데!","JPN":"ううっ、これはCRFの消耗が激しいからとっておいたのに！","ENG":"Hngh... I didn't want to use this because it drains too much CRF!","TWN":"呃，這個CRF消耗太大了，我一直捨不得用！"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_EARTHQUAKE_03","voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ESPR_C_GOETIA_IN_TRAILER_7-2"},{"id":"L40_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"……이 거대한 침식체 팔은 뭐야?","JPN":"……この巨大な侵食体の腕は何？","ENG":"...A giant C.O. arm?","TWN":"……這巨大的侵蝕體手臂是什麼？"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"정말 네가 불러낸 거야?","JPN":"本当にあんたが呼び出したの？","ENG":"Did you really summon that?","TWN":"真的是你召喚的嗎？"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"저택 지붕을 날려버렸어요! 이러면 분명 당신이 힘을 되찾을 거라고 했거든요!","JPN":"邸宅の屋根をふっ飛ばしました！　こうすればきっとあなたが力を取り戻せるって言われたから！","ENG":"I blew the roof off the mansion! That should help you regain your strength!","TWN":"我把屋子的屋頂給掀了！這樣一來你一定會恢復力量的！"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ESPR_C_GOETIA_IN_TRAILER_8-2"},{"id":"L44_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"……누가?","JPN":"……誰に？","ENG":"...Who told you that?","TWN":"……誰？"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"넌 중요한 그릇이니까.","JPN":"あなたは大事な器だから。","ENG":"You're an important vessel.","TWN":"你可是重要的器皿。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE","voice":"AB_UI_UNIT_VOICE_OPR_AGNES_COMMANDER_IN_TRAILER_7"},{"id":"L47_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"잘 먹고, 잘 자라고, 잘 살아남아야 하지 않겠어?","JPN":"よく食べて、すくすく育って、ちゃんと生き残ってもらわないと困るでしょう？","ENG":"You have to eat well, sleep well... and survive.","TWN":"要好好吃飯，好好睡覺，好好活下去，不是嗎？"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_OPR_AGNES_COMMANDER_IN_TRAILER_8"},{"id":"L48_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"멍멍이가 자기 목숨을 희생해서 성황청의 꼬맹이를 살리는 선택을 하다니.","JPN":"ワンちゃんが自分の命を犠牲にして、聖皇庁のチビちゃんを助ける選択をするなんて。","ENG":"To think Puppy sacrificed herself just to let the Holy Curia's little nun escape.","TWN":"狗狗竟然選擇犧牲自己的生命來救聖皇廳的小鬼。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"voice":"AB_UI_UNIT_VOICE_OPR_AGNES_COMMANDER_IN_TRAILER_9"},{"id":"L50_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"언니는 좀 서운하네.","JPN":"姉さんは少し寂しいわ。","ENG":"That stings my pride a little, you know.","TWN":"姊姊有點失落呢。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE","voice":"AB_UI_UNIT_VOICE_OPR_AGNES_COMMANDER_IN_TRAILER_10"},{"id":"L2_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"읏……. 제일 가능성 높은 선택이었어요.","JPN":"うっ……一番可能性が高い選択肢だったんです。","ENG":"Ngh... It was just the best move I could make.","TWN":"呃……這是最上算的選擇。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"언니도 제 성격, 알고 계시잖아요.","JPN":"姉さんも私の性格、知ってるでしょう。","ENG":"You know my nature.","TWN":"姊姊也知道我的性格吧。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"후훗, 모르겠는데?","JPN":"ふふっ、さあね？","ENG":"Haha. Do I?","TWN":"呵呵，不知道呢？"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"voice":"AB_UI_UNIT_VOICE_OPR_AGNES_COMMANDER_IN_TRAILER_11"},{"id":"L7_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"살아 있어서 다행이야. 멍멍아.","JPN":"生きていてよかったわ、ワンちゃん。","ENG":"I'm glad you're alive, Puppy.","TWN":"幸好狗狗還活著。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_OPR_AGNES_COMMANDER_IN_TRAILER_12"},{"id":"L11_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"이게 제일 승산이 높은 선택이었어요.","JPN":"これが一番勝ち目のある選択でした。","ENG":"This was the choice with the highest survival rate.","TWN":"這是勝算最高的選擇。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"멋대로 목숨을 건 건 사과드릴게요.","JPN":"勝手に命をかけたことは謝ります。","ENG":"I apologize for putting my life on the line.","TWN":"擅自冒險，我向你道歉。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"결과가 나쁘지 않았으니, 이번은 넘어가 줄게.","JPN":"結果が悪くなかったから、今回だけは大目に見てあげる。","ENG":"The outcome wasn't bad, so I'll let it slide this time.","TWN":"結果還不錯，這次就放過你吧。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_OPR_AGNES_COMMANDER_IN_TRAILER_13"},{"id":"L15_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"하지만 다음엔 이런 짓 하지 마.","JPN":"でも次はこんなことしちゃダメよ。","ENG":"But don't do it again.","TWN":"但是下次不要再做這種事。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_OPR_AGNES_COMMANDER_IN_TRAILER_14"},{"id":"L16_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"이제 잃는 건 지긋지긋하니까.","JPN":"もう失うのはうんざりだから。","ENG":"I'm tired of losing people.","TWN":"因為已經厭倦了失去。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_OPR_AGNES_COMMANDER_IN_TRAILER_15"},{"id":"L18_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"……네. 죄송해요.","JPN":"……はい、すみません。","ENG":"...Understood. I'm sorry.","TWN":"……啊，想起來了。不好意思。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"오늘은 만월이야. 멍멍이. 달빛이 상쾌하지?","JPN":"今日は満月よ、ワンちゃん。月明かりが気持ちいいでしょう？","ENG":"It's a full moon tonight, Puppy. Doesn't it feel refreshing?","TWN":"今天是月圓喔，狗狗。月光很耀眼吧？"},"stage":{"bg":"MOONLIGHT_01","bgm":"THEMA_CA_BLUE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE","voice":"AB_UI_UNIT_VOICE_OPR_AGNES_COMMANDER_IN_TRAILER_1"},{"id":"L22_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"만월엔 항상 짜증 나고 예민하기만 했었는데, 오늘은 기분이 좋네요.","JPN":"満月の日はいつもイライラして嫌だったけど、今日はいい気分です。","ENG":"Full moons always made me irritable and restless, but tonight... I feel good.","TWN":"月圓時總是煩躁又敏感，但今天心情很好呢。"},"stage":{"bg":"MOONLIGHT_01","bgm":"THEMA_CA_BLUE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ESPR_CA_BLUE_IN_TRAILER_15"},{"id":"L23_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"역시 사람은 참으면 안 된다니까요?","JPN":"やっぱり我慢はよくないですね。","ENG":"See? It's better to let loose sometimes.","TWN":"果然，人不能忍耐啊？"},"stage":{"bg":"MOONLIGHT_01","bgm":"THEMA_CA_BLUE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ESPR_CA_BLUE_IN_TRAILER_16-2"},{"id":"L24_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"좋아. 몸은 다 회복했고…… 시작해 볼까?","JPN":"よし、体は全部回復したし……始めてみるか？","ENG":"All right, I'm all healed up... Let's get started.","TWN":"好。身體已經恢復了……開始吧？"},"stage":{"bg":"MOONLIGHT_01","bgm":"THEMA_CA_BLUE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ESPR_CA_BLUE_IN_TRAILER_17-2"},{"id":"L25_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"마음껏 날뛰어봐, 멍멍이.","JPN":"好きなだけ暴れなさい、ワンちゃん。","ENG":"Go wild, Puppy.","TWN":"盡情地奔跑吧，狗狗。"},"stage":{"bg":"MOONLIGHT_01","bgm":"THEMA_CA_BLUE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_OPR_AGNES_COMMANDER_IN_TRAILER_2"},{"id":"L26_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"오늘만큼은 네가 야수가 되더라도 신경 쓰지 않을 테니.","JPN":"今日だけは、野獣になっても構わないから。","ENG":"Just for tonight, I won't care if you become a beast.","TWN":"今天就算你變成野獸，我也不會在意。"},"stage":{"bg":"MOONLIGHT_01","bgm":"THEMA_CA_BLUE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_OPR_AGNES_COMMANDER_IN_TRAILER_3"},{"id":"L27_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"의뢰인 루드윅 폰 에르헨.","JPN":"依頼人、ルードヴィヒ・フォン・ヘルヒェン。","ENG":"Ludwig von Herrchen.","TWN":"委託人路易先生。"},"stage":{"bg":"MOONLIGHT_01","bgm":"THEMA_CA_BLUE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ESPR_CA_BLUE_IN_TRAILER_18"},{"id":"L28_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"당신의 의뢰대로, 무슨 방법을 써서라도 악령을 제거한다.","JPN":"あなたの依頼通り、どんな手を使ってでも悪霊を排除する。","ENG":"Per the request, I will exorcise the evil spirit by any means necessary.","TWN":"按照你的委託，不管用什麼方法都會驅除惡靈。"},"stage":{"bg":"MOONLIGHT_01","bgm":"THEMA_CA_BLUE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ESPR_CA_BLUE_IN_TRAILER_19-2"},{"id":"L29_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"덧붙여, 의뢰인의 현재 상태는 보수를 지불할 수 없는 상황이라 판단.","JPN":"あと、依頼人は現在、報酬を支払えない状態と判断される。","ENG":"Furthermore, given the client's current state, I deem him unable to pay compensation.","TWN":"此外，判斷委託人目前的狀況無法支付報酬。"},"stage":{"bg":"MOONLIGHT_01","bgm":"THEMA_CA_BLUE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ESPR_CA_BLUE_IN_TRAILER_20-2"},{"id":"L30_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"퇴마 후 의뢰인의 모든 재산은 초월지식 학회의 종교학부에 귀속된다.","JPN":"退魔後、依頼人の全財産は超越知識学会の宗教学部に帰属する。","ENG":"As such, all assets of the client will be transferred to the Religion Department of the Society\xA0for\xA0Preternatural Research.","TWN":"驅魔後，委託人的所有財產將歸屬於超越學會的宗教學院。"},"stage":{"bg":"MOONLIGHT_01","bgm":"THEMA_CA_BLUE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ESPR_CA_BLUE_IN_TRAILER_21"},{"id":"L31_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"이의는 안 받아.","JPN":"異議は受けつけないよ。","ENG":"Objections will not be accepted.","TWN":"不接受異議。"},"stage":{"bg":"MOONLIGHT_01","bgm":"THEMA_CA_BLUE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ESPR_CA_BLUE_IN_TRAILER_22-2"},{"id":"L32_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"두들겨 맞을 준비나 하라고.","JPN":"ぼこぼこにされる覚悟でもしてな。","ENG":"Now, get ready to be beaten senseless.","TWN":"做好挨揍的準備吧。"},"stage":{"bg":"MOONLIGHT_01","bgm":"THEMA_CA_BLUE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ESPR_CA_BLUE_IN_TRAILER_23"}]`);export{e as default};